WITH
_cte_0_win_summary AS (
  SELECT * FROM match
),
_cte_1_win_summary AS (
  SELECT *, CASE WHEN home_team_goal > away_team_goal THEN home_team_api_id WHEN home_team_goal < away_team_goal THEN away_team_api_id ELSE NULL END AS winner_id FROM _cte_0_win_summary
),
_cte_2_win_summary AS (
  SELECT * FROM _cte_1_win_summary NATURAL LEFT JOIN team
),
_cte_3_win_summary AS (
  SELECT *, 1 AS wins FROM _cte_2_win_summary
),
_cte_4_win_summary AS (
  SELECT team_long_name, league_name, SUM(wins) AS wins_sum FROM _cte_3_win_summary GROUP BY team_long_name, league_name
),
_cte_5_win_summary AS (
  SELECT team_long_name AS Team, league_name, wins AS Wins FROM _cte_4_win_summary
),
_cte_6_win_summary AS (
  SELECT * FROM _cte_5_win_summary ORDER BY Wins ASC
),
_cte_7_win_summary AS (
  SELECT * FROM _cte_6_win_summary WHERE Wins > 50
)
SELECT * FROM _cte_7_win_summary

