WITH
_cte_0_homematch AS (
  SELECT * FROM match
),
_cte_1_homematch AS (
  SELECT *, home_team_goal - away_team_goal AS GD FROM _cte_0_homematch
),
_cte_2_homematch AS (
  SELECT home_team_api_id AS team_id, date, GD FROM _cte_1_homematch
),
_cte_3_homematch AS (
  SELECT * FROM _cte_2_homematch ORDER BY team_id ASC, date ASC
),
_cte_4_home_away_match AS (
  SELECT * FROM match
),
_cte_5_home_away_match AS (
  SELECT *, away_team_goal - home_team_goal AS GD FROM _cte_4_home_away_match
),
_cte_6_home_away_match AS (
  SELECT away_team_api_id AS team_id, date, GD FROM _cte_5_home_away_match
),
_cte_7_home_away_match AS (
  SELECT * FROM _cte_6_home_away_match ORDER BY team_id ASC, date ASC
),
_cte_8_home_away_match AS (
  SELECT * FROM _cte_7_home_away_match UNION ALL SELECT * FROM homematch
),
_cte_9_home_away_match AS (
  SELECT *, LAG(GD, 1) OVER (PARTITION BY team_id ORDER BY date) AS GD_lag FROM _cte_8_home_away_match
),
_cte_10_home_away_match AS (
  SELECT *, AVG(GD_lag) OVER (PARTITION BY team_id ORDER BY date ROWS BETWEEN 3 PRECEDING AND CURRENT ROW) AS pastgame_GD FROM _cte_9_home_away_match
)
SELECT * FROM _cte_10_home_away_match

